const $ = (s) => document.querySelector(s);
const $$ = (s) => [...document.querySelectorAll(s)];
let state = {
  logged: false,
  tab: "dashboard",
  status: null,
  snapshot: null,
  logs: [],
  logFilter: "important",
  showDebug: false,
  tables: [],
  table: "users",
  rows: [],
  loadedTable: "",
  loadingTable: false,
  loadSeq: 0,
  lastError: "",
  dbQuery: "",
  tableLimit: 100,
  consoleOutput: [],
  commandHistory: [],
  historyIndex: -1,
  maintenance: null,
  theme: localStorage.nvAdminTheme || "crimson",
  accent: localStorage.nvAdminAccent || "#e11b2f",
  density: localStorage.nvAdminDensity || "comfortable",
  fontSize: Number(localStorage.nvAdminFontSize || 14),
  radius: Number(localStorage.nvAdminRadius || 18),
};
function h(v = "") { return String(v).replace(/[&<>"']/g, (m) => ({ "&":"&amp;", "<":"&lt;", ">":"&gt;", '"':"&quot;", "'":"&#039;" })[m]); }
function fmtBytes(value = 0) { const n = Number(value || 0); if (n > 1024 * 1024 * 1024) return (n / 1024 / 1024 / 1024).toFixed(2) + " GB"; if (n > 1024 * 1024) return (n / 1024 / 1024).toFixed(1) + " MB"; if (n > 1024) return (n / 1024).toFixed(1) + " KB"; return n + " B"; }
function fmtTime(value) { if (!value) return "—"; try { return new Date(value).toLocaleString("ru-RU"); } catch { return "—"; } }
function ago(value) { if (!value) return "—"; const d = Date.now() - Number(value); if (d < 60000) return "только что"; if (d < 3600000) return Math.round(d / 60000) + " мин назад"; if (d < 86400000) return Math.round(d / 3600000) + " ч назад"; return Math.round(d / 86400000) + " д назад"; }
function toast(text) { const el = document.createElement("div"); el.className = "toast"; el.textContent = text; document.body.appendChild(el); setTimeout(() => el.remove(), 3000); }
function debounce(fn, wait = 120) { let timer = null; return (...args) => { clearTimeout(timer); timer = setTimeout(() => fn(...args), wait); }; }
function applyAdminTheme(){ document.documentElement.dataset.adminTheme = state.theme; document.documentElement.style.setProperty("--admin-accent", state.accent); document.documentElement.style.setProperty("--admin-radius", state.radius + "px"); document.documentElement.style.setProperty("--admin-font", state.fontSize + "px"); document.body.dataset.density = state.density; }
function rowFingerprint(rows) { return String((rows || []).length) + ":" + String(Object.keys((rows || [])[0] || {}).join(",")); }
function titlebar() { return `<div class="titlebar"><div class="brand"><span class="dot"></span><span>NightVault Server Admin</span><em>1.4.4</em></div><div class="win"><button id="min">−</button><button id="max">▢</button><button id="close">×</button></div></div>`; }
function bindWin() { $("#min")?.addEventListener("click", () => nvAdmin.minimize()); $("#max")?.addEventListener("click", () => nvAdmin.toggleFull()); $("#close")?.addEventListener("click", () => nvAdmin.close()); }
function renderLogin(){ applyAdminTheme(); app.innerHTML = titlebar() + `<div class="login"><div class="loginBox"><div class="orb"></div><h1>NightVault Admin Pro</h1><p>Центр управления сервером, Radmin/LAN, backup, тесты, пользователи и релизы.</p><input id="u" class="field" placeholder="Логин" value="admin"><input id="p" class="field" type="password" placeholder="Пароль"><button class="btn" id="login">Войти</button><p class="muted">NightVault 1.4.4 — Messenger Features Update.</p></div></div>`; bindWin(); $("#login").onclick = login; $("#p").addEventListener("keydown", e => { if (e.key === "Enter") login(); }); }
async function login(){ const res = await nvAdmin.login({ username: $("#u").value, password: $("#p").value }); if (!res.ok) return toast(res.message || "Ошибка входа"); state.logged = true; await refreshAll(); render(); }
async function refreshAll(){ try { state.status = await nvAdmin.status(); if (state.logged) { state.logs = await nvAdmin.logs().catch(() => []); state.tables = await nvAdmin.dbTables().catch(() => []); state.snapshot = await nvAdmin.snapshot().catch(() => null); state.maintenance = await nvAdmin.maintenanceGet().catch(() => null); } } catch {} }
function navButton(id, icon, text) { return `<button class="${state.tab === id ? "active" : ""}" onclick="switchAdminTab('${id}')">${icon} <span>${text}</span></button>`; }
function switchAdminTab(id){ state.tab = id; state.lastError = ""; render(); }
function layout(content){ applyAdminTheme(); const st = state.status?.server || {}; const snap = state.snapshot || {}; app.innerHTML = titlebar() + `<div class="app adminPro"><nav class="nav"><div class="serverCard"><b>NightVault</b><p class="muted">${h(st.url || state.status?.url || "не запущен")}</p><span class="pill ${st.ok ? "ok" : "warn"}">${st.ok ? "● online" : "○ offline"}</span><small>${h(snap.version || state.status?.version || "1.4.4")}</small></div>${navButton("dashboard", "📊", "Dashboard")}${navButton("server", "🌐", "Radmin/LAN")}${navButton("console", "⌁", "Console")}${navButton("logs", "📜", "Logs")}${navButton("users", "👥", "Users")}${navButton("sessions", "🖥", "Sessions")}${navButton("data", "🗄", "Database")}${navButton("backups", "🧰", "Backups")}${navButton("testing", "🧪", "Tests")}${navButton("updates", "🚀", "Updates")}${navButton("security", "🛡", "Security")}${navButton("settings", "⚙️", "Settings")}</nav><main class="content"><div class="topbar"><b>${h(tabTitle())}</b><span class="muted">${h(st.message || "Admin Pro")}</span><button class="btn ghost small" id="refreshTop">Обновить</button></div>${content}</main></div>`; bindWin(); $("#refreshTop")?.addEventListener("click", async () => { await refreshAll(); render(); }); }
function tabTitle(){ return ({ dashboard:"Dashboard", server:"Radmin/LAN Helper", console:"Admin Console 2.0", logs:"Log Center", users:"Users Manager", sessions:"Sessions & Devices", data:"Database Viewer", backups:"Backup Manager", testing:"Test Center 2.0", updates:"Release / Update Center", security:"Security Panel", settings:"Admin Settings" })[state.tab] || "Admin"; }
function render(){ try { if (!state.logged) return renderLogin(); const routes = { dashboard: renderDashboard, server: renderServer, console: renderConsole, logs: renderLogs, users: renderUsers, sessions: renderSessions, data: renderData, backups: renderBackups, testing: renderTesting, updates: renderUpdates, security: renderSecurity, settings: renderSettings }; return (routes[state.tab] || renderDashboard)(); } catch(e) { console.error(e); app.innerHTML = titlebar() + `<div class="app"><main class="content"><section class="panel"><h2>Ошибка отрисовки</h2><p class="muted">${h(e.message || e)}</p><button class="btn" onclick="render()">Повторить</button></section></main></div>`; bindWin(); } }
function metricCard(icon, title, value, sub = "") { return `<div class="metric"><b>${icon} ${h(title)}</b><strong>${h(value)}</strong><small>${h(sub)}</small></div>`; }
function renderDashboard(){ const s = state.snapshot || {}; const server = state.status?.server || {}; const health = s.health || {}; layout(`<section class="panel heroPanel"><div><h2>NightVault 1.4.4 — Admin Pro</h2><p class="muted">Состояние сервера, Radmin/LAN, база, пользователи, сокеты, ошибки, backup и релизы в одном месте.</p></div><div class="rowActions"><button class="btn" onclick="quickStartServer()">Запустить сервер</button><button class="btn ghost" onclick="copyTesterGuide()">Инструкция тестерам</button></div></section><section class="metricsGrid">${metricCard(server.ok ? "🟢" : "🔴", "Сервер", server.ok ? "работает" : "остановлен", server.url || state.status?.url || "—")}${metricCard("🌐", "Radmin URL", s.radmin?.publicUrl || server.url || "—", "Host " + (s.radmin?.host || "0.0.0.0"))}${metricCard("👥", "Пользователи", s.counts?.users || 0, "online: " + (s.counts?.online || 0))}${metricCard("💬", "Сообщения", s.counts?.messages || 0, "сегодня: " + (s.counts?.messagesToday || 0))}${metricCard("📦", "База", fmtBytes(health.dbSize || 0), "uploads: " + fmtBytes(health.uploadsSize || 0))}${metricCard("⚠", "Ошибки", s.errors?.lastHour || 0, s.errors?.lastError || "нет ошибок")}${metricCard("🔌", "WebSocket", s.counts?.sockets || 0, "активных соединений")}${metricCard("🧰", "Последний backup", s.backups?.latest || "—", (s.backups?.count || 0) + " файлов")}</section>${renderWarnings(s)}<section class="panel"><h3>События сервера</h3><div class="logList compact">${(state.logs || []).slice(-8).reverse().map(logLine).join("") || "<p class=muted>Логов пока нет.</p>"}</div></section>`); }
function renderWarnings(s){ const warnings = s.warnings || []; if (!warnings.length) return `<section class="panel okPanel">✅ Предупреждений нет. Сервер выглядит стабильно.</section>`; return `<section class="panel warnPanel"><h3>Предупреждения</h3>${warnings.map(w => `<div class="warning">⚠ ${h(w)}</div>`).join("")}</section>`; }
async function quickStartServer(){ const r = await nvAdmin.startServer(); toast(r.message || "Сервер запущен"); await refreshAll(); render(); }
function testerText(){ const s = state.snapshot || {}; const url = s.radmin?.publicUrl || state.status?.server?.url || "http://26.4.1.76:3000"; return `1. Подключись к Radmin VPN\n2. Запусти NightVault\n3. В поле сервера введи: ${url}\n4. Нажми сохранить и зарегистрируй аккаунт`; }
async function copyTesterGuide(){ const text = testerText(); try { await navigator.clipboard.writeText(text); toast("Инструкция скопирована"); } catch { toast(text); } }
function renderServer(){ const s = state.snapshot || {}; const r = s.radmin || {}; layout(`<section class="panel"><div class="panelHead"><div><h2>Radmin/LAN Helper 2.0</h2><p class="muted">Запуск сервера на 0.0.0.0 и быстрая инструкция для друзей.</p></div><div class="rowActions"><button class="btn" id="start">Запустить сервер для друзей</button><button class="btn ghost" id="stop">Остановить</button></div></div><div class="radminBox"><b>Сервер для тестеров</b><code>${h(r.publicUrl || state.status?.server?.url || "http://26.4.1.76:3000")}</code><div class="checkList"><span>✅ Host: ${h(r.host || "0.0.0.0")}</span><span>✅ Port: ${h(r.port || "3000")}</span><span>${state.status?.server?.ok ? "✅" : "⚠"} Сервер ${state.status?.server?.ok ? "запущен" : "остановлен"}</span><span>⚠ Firewall: проверить через PowerShell/Windows</span></div><textarea class="field" rows="5" readonly>${h(testerText())}</textarea><div class="rowActions"><button class="btn ghost" id="copyGuide">Скопировать инструкцию</button><button class="btn ghost" id="health">Проверить /api/health</button></div></div></section>`); $("#start").onclick = quickStartServer; $("#stop").onclick = async () => { const r = await nvAdmin.stopServer(); toast(r.message); await refreshAll(); render(); }; $("#copyGuide").onclick = copyTesterGuide; $("#health").onclick = async () => { const out = await nvAdmin.command("health"); toast(out.ok ? "Health OK" : "Health error"); state.consoleOutput.push({ command:"health", result:out }); }; }
function renderConsole(){ layout(`<section class="panel consolePanel"><div class="panelHead"><div><h2>Admin Console 2.0</h2><p class="muted">История команд, Tab-подсказки, export/copy вывода.</p></div><div class="rowActions"><button class="btn ghost" id="copyConsole">Копировать</button><button class="btn ghost" id="clearConsole">clear</button></div></div><div class="terminal" id="terminal">${state.consoleOutput.map(consoleLine).join("") || `<div class="termHelp">Введите <b>help</b>, <b>stats</b>, <b>users</b>, <b>backup list</b>, <b>release check</b>, <b>radmin</b>.</div>`}</div><div class="commandLine"><span>admin&gt;</span><input id="cmd" class="field" placeholder="help / stats / users / backup list / test all"><button class="btn" id="run">Run</button></div></section>`); const input = $("#cmd"); const run = async () => { const c = input.value.trim(); if (!c) return; state.commandHistory.push(c); state.historyIndex = state.commandHistory.length; input.value = ""; const r = await nvAdmin.command(c); state.consoleOutput.push({ command:c, result:r }); if (state.consoleOutput.length > 120) state.consoleOutput = state.consoleOutput.slice(-120); renderConsole(); setTimeout(() => $("#terminal")?.scrollTo(0,999999), 0); }; $("#run").onclick = run; input.addEventListener("keydown", e => { if (e.key === "Enter") run(); if (e.key === "ArrowUp") { e.preventDefault(); state.historyIndex = Math.max(0, state.historyIndex - 1); input.value = state.commandHistory[state.historyIndex] || ""; } if (e.key === "ArrowDown") { e.preventDefault(); state.historyIndex = Math.min(state.commandHistory.length, state.historyIndex + 1); input.value = state.commandHistory[state.historyIndex] || ""; } if (e.key === "Tab") { e.preventDefault(); input.value = autocompleteCommand(input.value); } }); input.focus(); $("#clearConsole").onclick = () => { state.consoleOutput = []; renderConsole(); }; $("#copyConsole").onclick = async () => { const text = state.consoleOutput.map(x => `> ${x.command}\n${JSON.stringify(x.result, null, 2)}`).join("\n\n"); await navigator.clipboard?.writeText(text).catch(()=>{}); toast("Вывод скопирован"); }; }
function autocompleteCommand(v){ const list = ["help","stats","health","ports","radmin","version","uptime","users","online","info user ","sessions ","devices ","contacts ","chats ","files ","logs errors","backup list","backup create","backup export","release check","security status","test all","broadcast ","clear"]; const hit = list.find(x => x.startsWith(String(v || "").toLowerCase())); return hit || v; }
function consoleLine(item){ return `<div class="termBlock"><div class="termCmd">&gt; ${h(item.command)}</div><pre>${h(item.result?.text || JSON.stringify(item.result?.data ?? item.result, null, 2))}</pre></div>`; }
function logLine(l){ return `<div class="log ${h(l.level)}"><span class="time">${h(l.time)}</span> [${h(l.level)}] ${h(l.text)}</div>`; }
function logCategory(l){ const t = String(l.text || "").toLowerCase(); if (/error|failed|ошиб|exception/.test(t) || l.level === "error") return "errors"; if (/security|2fa|token|session|login|register/.test(t)) return "auth"; if (/user|registered|profile/.test(t)) return "users"; if (/message|сообщ/.test(t)) return "messages"; if (/contact|заявк/.test(t)) return "contacts"; if (/group|chat_create|role/.test(t)) return "groups"; if (/file|upload|media/.test(t)) return "files"; if (/polling|ws-ticket|get \/api\/contacts|get \/api\/chats/.test(t)) return "polling"; if (/debug/.test(t)) return "debug"; return "important"; }
function filteredLogs(){ return (state.logs || []).filter(l => { const cat = logCategory(l); if (!state.showDebug && ["polling","debug"].includes(cat)) return false; if (state.logFilter === "all") return true; if (state.logFilter === "important") return !["polling","debug"].includes(cat); return cat === state.logFilter; }); }
function renderLogs(){ const filters = ["important","all","auth","users","messages","contacts","groups","files","security","errors","server","debug","polling"]; layout(`<section class="panel"><div class="panelHead"><div><h2>Log Center 2.0</h2><p class="muted">Полезные логи без polling-мусора. Debug можно включить вручную.</p></div><label class="switch"><input id="debugToggle" type="checkbox" ${state.showDebug ? "checked" : ""}> Показывать debug/polling</label></div><div class="filterRow">${filters.map(f => `<button class="chip ${state.logFilter === f ? "active" : ""}" onclick="state.logFilter='${f}';renderLogs()">${h(f)}</button>`).join("")}</div><div class="logList">${filteredLogs().slice(-260).reverse().map(logLine).join("") || "<p class=muted>Нет логов по фильтру.</p>"}</div></section>`); $("#debugToggle").onchange = e => { state.showDebug = e.target.checked; renderLogs(); }; }
function renderUsers(){ const users = state.snapshot?.users || []; layout(`<section class="panel"><div class="panelHead"><div><h2>Users Manager</h2><p class="muted">Пользователи, online, IP, устройства, сессии, 2FA, чаты, файлы и риск.</p></div><button class="btn ghost" onclick="runConsoleQuick('users')">Команда users</button></div><div class="adminTable"><table><thead><tr><th>Ник</th><th>Online</th><th>IP</th><th>Устр.</th><th>Сессий</th><th>Чатов</th><th>Сообщ.</th><th>Файлов</th><th>2FA</th><th>Регистрация</th><th>Действия</th></tr></thead><tbody>${users.map(u => `<tr><td><b>@${h(u.username)}</b><small>${h(u.displayName || "")}</small></td><td>${u.online ? "🟢" : "⚫"}<small>${h(ago(u.lastSeen))}</small></td><td>${h(u.ip || "—")}</td><td>${h(u.devices || 0)}</td><td>${h(u.sessions || 0)}</td><td>${h(u.chats || 0)}</td><td>${h(u.messages || 0)}</td><td>${h(u.files || 0)}</td><td>${u.twoFactor ? "✅" : "—"}</td><td>${h(fmtTime(u.createdAt))}</td><td><button class="btn ghost small" onclick="runConsoleQuick('info user ${h(u.username)}')">info</button><button class="btn ghost small" onclick="runConsoleQuick('sessions ${h(u.username)}')">sessions</button></td></tr>`).join("")}</tbody></table></div></section>`); }
async function runConsoleQuick(command){ const r = await nvAdmin.command(command); state.consoleOutput.push({ command, result:r }); state.tab = "console"; renderConsole(); }
function renderSessions(){ const sessions = state.snapshot?.sessions || []; const devices = state.snapshot?.devices || []; layout(`<section class="panel"><h2>Sessions & Devices Manager</h2><p class="muted">Мульти-клиентность, IP, deviceId, trusted/untrusted, E2EE key status.</p><div class="split2"><div><h3>Сессии</h3><div class="adminTable"><table><thead><tr><th>User</th><th>IP</th><th>Device</th><th>Created</th><th>Last</th><th>Refresh</th></tr></thead><tbody>${sessions.map(s => `<tr><td>@${h(s.username)}</td><td>${h(s.ip || "—")}</td><td>${h(s.device || s.userAgent || "NightVault")}</td><td>${h(fmtTime(s.createdAt))}</td><td>${h(fmtTime(s.lastUsedAt))}</td><td>${s.refreshValid ? "✅" : "⚠"}</td></tr>`).join("")}</tbody></table></div></div><div><h3>Устройства E2EE</h3><div class="adminTable"><table><thead><tr><th>User</th><th>Device ID</th><th>Trusted</th><th>Key</th><th>Last seen</th></tr></thead><tbody>${devices.map(d => `<tr><td>@${h(d.username)}</td><td><code>${h(d.id || d.deviceId || "—")}</code></td><td>${d.trusted ? "✅" : "—"}</td><td>${d.keyStatus || "public"}</td><td>${h(fmtTime(d.lastSeenAt || d.lastSeen))}</td></tr>`).join("")}</tbody></table></div></div></div></section>`); }
function safeCell(value){ let text = typeof value === "string" ? value : JSON.stringify(value); if (text == null) text = ""; text = String(text); return text.length > 420 ? text.slice(0,420)+"…" : text; }
async function selectTable(name){ if(!name) return; const seq = ++state.loadSeq; state.table=name; state.loadingTable=true; state.lastError=""; state.rows=[]; renderData(); try{ const limit = Math.min(Math.max(Number(state.tableLimit || 100),25),500); const rows = await nvAdmin.dbRead(name, limit); if(seq!==state.loadSeq) return; state.rows=Array.isArray(rows)?rows:[]; state.loadedTable=name; state.tableSeqText=rowFingerprint(state.rows); } catch(e){ if(seq!==state.loadSeq) return; state.lastError=e.message||String(e); toast("Таблица не открылась: "+state.lastError); } finally { if(seq===state.loadSeq){ state.loadingTable=false; renderData(); } } }
function renderTableBody(){ const allRows=Array.isArray(state.rows)?state.rows:[]; const q=String(state.dbQuery||"").toLowerCase(); const rows=q?allRows.filter(r=>JSON.stringify(r||{}).toLowerCase().includes(q)):allRows; const cols=[...new Set(rows.flatMap(r=>Object.keys(r||{})))].slice(0,14); const body = state.loadingTable ? '<div class="emptyTable"><span class="miniLoader"></span> Загрузка таблицы…</div>' : state.lastError ? `<div class="emptyTable errorBox">${h(state.lastError)}</div>` : rows.length ? `<table><thead><tr>${cols.map(c=>`<th onclick="sortTableBy('${h(c)}')">${h(c)}</th>`).join("")}</tr></thead><tbody>${rows.map((r,i)=>`<tr>${cols.map(c=>{const v=safeCell((r||{})[c]);return `<td title="${h(v)}">${h(v)}</td>`}).join("")}<td><button class="btn ghost small" onclick="copyRow(${i})">copy</button></td></tr>`).join("")}</tbody></table>` : '<div class="emptyTable">В таблице нет записей.</div>'; return {body, rows, allRows}; }
function renderData(){ if(state.tables.length && !state.tables.includes(state.table)) state.table=state.tables[0]; const buttons=state.tables.map(t=>`<button class="${state.table===t?'active':''}" onclick="selectTable('${h(t)}')" title="${h(t)}">${h(t)}</button>`).join(""); const rendered=renderTableBody(); const limits=[25,50,100,200,500].map(n=>`<option value="${n}" ${Number(state.tableLimit)===n?'selected':''}>${n} строк</option>`).join(""); layout(`<section class="panel"><div class="panelHead"><div><h2>Database Viewer 2.0</h2><p class="muted">Read-only, поиск, лимит, сортировка, копирование строк, экспорт JSON/CSV.</p></div><div class="rowActions"><button class="btn ghost" id="reload">Обновить</button><button class="btn ghost" id="exportJson">Export JSON</button><button class="btn ghost" id="exportCsv">Export CSV</button></div></div><div class="dataLayout"><div class="tables">${buttons||'<p class="muted">Нет таблиц</p>'}</div><div class="dbMain"><div class="tableToolbar"><input id="dbSearch" class="field" placeholder="Фильтр по загруженным строкам" value="${h(state.dbQuery||"")}"><select id="dbLimit" class="field slim">${limits}</select><span class="muted">${rendered.rows.length}/${rendered.allRows.length} строк</span></div><div class="tableWrap">${rendered.body}</div></div></div></section>`); $("#reload").onclick=async()=>{state.loadedTable=""; await refreshAll(); if(state.table) await selectTable(state.table); else renderData();}; const search=$("#dbSearch"); if(search) search.oninput=debounce(e=>{state.dbQuery=e.target.value; renderData();},90); const limit=$("#dbLimit"); if(limit) limit.onchange=async e=>{state.tableLimit=Number(e.target.value||100); state.loadedTable=""; await selectTable(state.table);}; $("#exportJson").onclick = () => downloadText(`${state.table}.json`, JSON.stringify(state.rows, null, 2)); $("#exportCsv").onclick = () => downloadText(`${state.table}.csv`, toCsv(state.rows)); if(state.table && state.loadedTable!==state.table && !state.loadingTable){ setTimeout(()=>selectTable(state.table).catch(()=>{}),30); } }
function toCsv(rows){ const cols=[...new Set((rows||[]).flatMap(r=>Object.keys(r||{})))]; return [cols.join(","), ...(rows||[]).map(r=>cols.map(c=>JSON.stringify((r||{})[c] ?? "")).join(","))].join("\n"); }
function downloadText(name, text){ const a=document.createElement("a"); a.href=URL.createObjectURL(new Blob([text],{type:"text/plain"})); a.download=name; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href), 1000); }
function copyRow(i){ navigator.clipboard?.writeText(JSON.stringify(state.rows[i] || {}, null, 2)); toast("Строка скопирована"); }
function sortTableBy(col){ state.rows = [...state.rows].sort((a,b)=>String(a?.[col]??"").localeCompare(String(b?.[col]??""))); renderData(); }
function renderBackups(){ const b = state.snapshot?.backups || {}; layout(`<section class="panel"><div class="panelHead"><div><h2>Backup Manager 2.0</h2><p class="muted">.nvbackup v2: manifest, database, uploads, safe config, checksum.</p></div><div class="rowActions"><button class="btn" id="createBackup">Создать backup</button><button class="btn ghost" id="exportBackup">Скачать/выгрузить</button><button class="btn ghost" id="importBackup">Импортировать</button></div></div><div class="metricsGrid">${metricCard("🧰","Backup files", b.count || 0, "последний: " + (b.latest || "—"))}${metricCard("✅","Проверка", "checksum", "manifest + db + uploads")}${metricCard("↩","Rollback", "auto", "перед импортом")}</div><div class="adminTable"><table><thead><tr><th>Файл</th><th>Размер</th><th>Дата</th><th>Действия</th></tr></thead><tbody>${(b.items||[]).map(x=>`<tr><td>${h(x.name)}</td><td>${h(fmtBytes(x.size))}</td><td>${h(fmtTime(x.mtime))}</td><td><button class="btn ghost small" onclick="runConsoleQuick('backup verify ${h(x.name)}')">verify</button></td></tr>`).join("")}</tbody></table></div></section>`); $("#createBackup").onclick = async()=>{ const r=await nvAdmin.backupCreate(); toast(r.text || r.path || "Backup создан"); await refreshAll(); renderBackups(); }; $("#exportBackup").onclick = async()=>{ const r=await nvAdmin.exportData(); toast(r.canceled?"Отменено":"Выгружено: "+r.path); await refreshAll(); renderBackups(); }; $("#importBackup").onclick = async()=>{ if(!confirm("Импорт заменит текущую серверную базу. Перед импортом будет создан safety-backup. Продолжить?")) return; const r=await nvAdmin.importData(); toast(r.canceled?"Отменено":"Импортировано: "+r.path); await refreshAll(); renderBackups(); }; }
function renderTesting(){ const tests=["sqlite","migrations","backup","server","radmin","websocket","register","login","refresh","contacts","message","group","group-avatar","files","image","voice","e2ee","release","all"]; layout(`<section class="panel"><div class="panelHead"><div><h2>Настоящий Admin Test Center / Test Center 2.0</h2><p class="muted">Тесты SQLite, миграций, backup, Radmin, WebSocket, сообщений, файлов, E2EE и релизов.</p></div><button class="btn" onclick="runTest('all')">Запустить все тесты</button></div><div class="grid">${tests.map(t=>`<button class="btn ghost testBtn" onclick="runTest('${t}')"><b>${h(t)}</b><span class="muted">status / duration / details / error</span></button>`).join("")}</div><pre id="result" class="testResult">Ожидание.</pre></section>`); }
async function runTest(id){ const out=$("#result"); try{ if(out) out.textContent="Выполняю тест "+id+"…"; const r=await nvAdmin.runTest(id); if(out) out.textContent=JSON.stringify(r,null,2); await refreshAll(); } catch(e){ if(out) out.textContent="Ошибка теста: "+(e.message||e); toast("Тест не выполнен: "+(e.message||e)); } }
function renderUpdates(){ const u = state.snapshot?.release || {}; layout(`<section class="panel"><div class="panelHead"><div><h2>Release / Update Center</h2><p class="muted">Проверка GitHub Release, latest.yml, installer, portable, blockmap и workflow.</p></div><button class="btn" id="releaseCheck">Проверить релиз</button></div><div class="metricsGrid">${metricCard("🔖","Current", u.currentVersion || "1.4.4", "tag v"+(u.currentVersion||"1.4.4"))}${metricCard("GitHub","Repo", u.repo || "Onmaynec/NightVault", "Actions + Releases")}${metricCard("📄","latest.yml", u.latestYml ? "OK" : "check", "нужен для автообновлений")}${metricCard("💿","Installer", u.installer ? "OK" : "check", "NightVault-Setup.exe")}${metricCard("🧱","Blockmap", u.blockmap ? "OK" : "check", "delta update")}${metricCard("📦","Portable", u.portable ? "OK" : "check", "x64 portable")}</div><pre class="testResult">${h(JSON.stringify(u, null, 2))}</pre></section>`); $("#releaseCheck").onclick = async()=>{ const r = await nvAdmin.releaseCheck(); toast(r.ok?"Release-audit OK":"Release-audit проверь"); state.consoleOutput.push({command:"release check",result:r}); await refreshAll(); renderUpdates(); }; }
function renderSecurity(){ const s = state.snapshot?.security || {}; const errors = state.snapshot?.errors || {}; layout(`<section class="panel"><h2>Security Panel</h2><div class="metricsGrid">${metricCard("🔑","Admin password", s.adminPasswordStatus || "configured", "PBKDF2")}${metricCard("2FA","Users", s.twoFactorUsers || 0, "включили 2FA")}${metricCard("🚫","Failed logins", s.failedLogins || 0, "последний час")}${metricCard("🧭","Suspicious IPs", s.suspiciousIps || 0, "rate/security")}${metricCard("🖥","Active sessions", s.activeSessions || 0, "refresh tokens")}${metricCard("🔐","E2EE devices", s.e2eeDevices || 0, "key status")}</div><h3>Error Registry</h3><div class="logList">${(errors.items||[]).map(logLine).join("") || "<p class=muted>Ошибок нет.</p>"}</div><div class="rowActions"><button class="btn ghost" onclick="runConsoleQuick('security status')">security status</button><button class="btn ghost" onclick="runConsoleQuick('logs errors')">logs errors</button><button class="btn ghost" onclick="nvAdmin.debugReport().then(r=>toast('Debug report: '+r.path))">Создать debug report</button></div></section>`); }
function renderSettings(){ layout(`<section class="panel settingsForm"><h2>Admin Themes 2.0</h2><p class="muted">Тема, accent, density, font size, radius, console/table density.</p><div class="settingsGrid"><label>Тема<select id="theme" class="field"><option>crimson</option><option>crimson-soft</option><option>crimson-neon</option><option>obsidian-red</option><option>aurora</option><option>blackout</option><option>matrix</option><option>ivory</option></select></label><label>Accent color<input id="accent" class="field" type="color" value="${h(state.accent)}"></label><label>Density<select id="density" class="field"><option>comfortable</option><option>compact</option><option>spacious</option></select></label><label>Font size<input id="fontSize" class="field" type="number" min="12" max="18" value="${h(state.fontSize)}"></label><label>Radius<input id="radius" class="field" type="number" min="8" max="28" value="${h(state.radius)}"></label></div><div class="rowActions"><button class="btn" id="saveTheme">Сохранить визуал</button></div></section><section class="panel settingsForm"><h2>Maintenance Mode</h2><p class="muted">Безопасный режим перед импортом backup или обновлением.</p><label class="switch"><input id="maintEnabled" type="checkbox" ${state.maintenance?.enabled?'checked':''}> Включить maintenance mode</label><input id="maintMsg" class="field" placeholder="Сообщение пользователям" value="${h(state.maintenance?.message || "Сервер на обслуживании")}"><div class="rowActions"><button class="btn" id="saveMaint">Сохранить maintenance</button></div></section><section class="panel settingsForm"><h2>Пароль администратора</h2><input id="old" class="field" type="password" placeholder="Текущий пароль"><input id="next" class="field" type="password" placeholder="Новый пароль"><button class="btn" id="savePass">Сменить пароль</button></section>`); $("#theme").value=state.theme; $("#density").value=state.density; $("#saveTheme").onclick=()=>{ state.theme=$("#theme").value; state.accent=$("#accent").value; state.density=$("#density").value; state.fontSize=Number($("#fontSize").value||14); state.radius=Number($("#radius").value||18); localStorage.nvAdminTheme=state.theme; localStorage.nvAdminAccent=state.accent; localStorage.nvAdminDensity=state.density; localStorage.nvAdminFontSize=state.fontSize; localStorage.nvAdminRadius=state.radius; toast("Настройки админки сохранены"); renderSettings(); }; $("#saveMaint").onclick=async()=>{ const r=await nvAdmin.maintenanceSet({ enabled:$("#maintEnabled").checked, message:$("#maintMsg").value, allowLogin:true, allowRead:true, blockWrites:$("#maintEnabled").checked, blockRegistration:$("#maintEnabled").checked }); state.maintenance=r; toast("Maintenance сохранён"); await refreshAll(); renderSettings(); }; $("#savePass").onclick=async()=>{try{await nvAdmin.changePassword({currentPassword:$("#old").value,nextPassword:$("#next").value});toast("Пароль изменён");}catch(e){toast(e.message||String(e));}}; }
function renderBackupsShort(){ return ""; }
function initLive(){ if(window.__nvAdminLive138) return; window.__nvAdminLive138=true; nvAdmin.onLog((line)=>{ state.logs.push(line); if(state.logs.length>1200) state.logs=state.logs.slice(-1200); if(["logs","dashboard"].includes(state.tab)) render(); }); setInterval(async()=>{ if(!state.logged) return; const active=document.activeElement; const isTyping=active && ["INPUT","TEXTAREA","SELECT"].includes(active.tagName); if(isTyping && !["dashboard","logs"].includes(state.tab)) return; await refreshAll(); if(["dashboard","server","logs","users","sessions","backups","updates","security"].includes(state.tab)) render(); }, 1500); }
initLive();
window.switchAdminTab = switchAdminTab;
window.render = render;
window.runTest = runTest;
window.state = state;
window.copyRow = copyRow;
window.sortTableBy = sortTableBy;
window.selectTable = selectTable;
window.runConsoleQuick = runConsoleQuick;
render();
function debugReport() { return nvAdmin.debugReport(); }
function then() { return null; }

