/* NightVault 1.4.4 — inline admin action bridge */
window.saveAdminVisual = async function saveAdminVisual(){
  state.theme = document.querySelector('#adminTheme')?.value || document.querySelector('#theme')?.value || state.theme;
  state.accent = document.querySelector('#adminAccent')?.value || document.querySelector('#accent')?.value || state.accent;
  state.density = document.querySelector('#adminDensity')?.value || document.querySelector('#density')?.value || state.density;
  state.fontSize = Number(document.querySelector('#adminFontSize')?.value || document.querySelector('#fontSize')?.value || state.fontSize || 14);
  state.radius = Number(document.querySelector('#adminRadius')?.value || document.querySelector('#radius')?.value || state.radius || 18);
  localStorage.nvAdminTheme = state.theme;
  localStorage.nvAdminAccent = state.accent;
  localStorage.nvAdminDensity = state.density;
  localStorage.nvAdminFontSize = String(state.fontSize);
  localStorage.nvAdminRadius = String(state.radius);
  applyAdminTheme();
  toast('Визуал админки сохранён');
};
window.saveMaintenance = async function saveMaintenance(){
  const payload = { enabled: Boolean(document.querySelector('#maintEnabled')?.checked), message: document.querySelector('#maintMessage')?.value || document.querySelector('#maintMsg')?.value || 'Сервер на обслуживании', allowLogin:true, allowRead:true, blockWrites:Boolean(document.querySelector('#maintEnabled')?.checked), blockRegistration:Boolean(document.querySelector('#maintEnabled')?.checked) };
  state.maintenance = await nvAdmin.maintenanceSet(payload);
  toast('Maintenance mode сохранён');
  await refreshAll();
};
window.changePassword = async function changePassword(){
  const currentPassword = document.querySelector('#oldPass')?.value || document.querySelector('#old')?.value || '';
  const nextPassword = document.querySelector('#newPass')?.value || document.querySelector('#next')?.value || '';
  const r = await nvAdmin.changePassword({ currentPassword, nextPassword });
  toast(r?.ok ? 'Пароль администратора изменён' : (r?.message || 'Пароль не изменён'));
};
window.runAdminCommand = async function runAdminCommand(command){
  const result = await nvAdmin.command(command);
  state.consoleOutput.push({ command, result });
  toast(result?.ok === false ? (result.text || 'Команда завершилась ошибкой') : 'Команда выполнена');
  return result;
};

